  poppy: { diff: "EVEN", tone: "#e8b84b", tldr: "Poke her \u2014 E-dash her engage, dodge her E.", breakdown: "Q-poke from range, E-dash out of her engage, and dodge her E wall-stun.", dos: ["Q-poke from range", "E-dash out of her engage", "Dodge her E wall-stun"], donts: ["Get E-wall-stunned", "Get R-knocked mid-combo", "Get stuck in melee"], key: { slot: "E", name: "Heroic Charge", cd: "14s", note: "Wall-pin stun. Dodge it.", winT: "CHARGE DOWN", winS: "Stun-stack + R her." }, hold: "Hold E to dash out of her engage \u2014 deny her E before she pins you.", tip: "Q-poke from range, E-dash out of her engage, and dodge her E wall-stun.", win: "Poke her and dash her engage." },
