  zac: { diff: "EVEN", tone: "#e8b84b", tldr: "Build MR \u2014 Q-poke, E-dash his E, anti-heal.", breakdown: "Build MR, Q-poke from range, E-dash out of his E slingshot, and anti-heal his sustain.", dos: ["Build MR", "Q-poke from range", "Anti-heal his sustain"], donts: ["Let him eat blobs", "Get E-knocked-up", "Get stuck in melee"], key: { slot: "E", name: "Elastic Slingshot", cd: "16s", note: "His engage. E-dash/dodge it.", winT: "SLINGSHOT DOWN", winS: "Stun-stack + R him." }, hold: "Hold E to dash out of his E slingshot \u2014 build MR; Q-poke and anti-heal his sustain.", tip: "Build MR, Q-poke from range, E-dash out of his E, and anti-heal his sustain.", win: "Build MR and poke him out." },
