  akali: { diff: "EVEN", tone: "#e8b84b", tldr: "Build MR \u2014 Q-poke off shroud, E-dash her all-in.", breakdown: "Build MR, Q-poke her off her shroud, and E-dash out of her all-in.", dos: ["Build MR", "Q-poke off her shroud", "E-dash out of her all-in"], donts: ["Fight her in the shroud", "Get Q-poked down", "Get stuck in melee"], key: { slot: "W", name: "Twilight Shroud", cd: "18s", note: "Untargetable inside. Poke when down.", winT: "SHROUD DOWN", winS: "Stun-stack + R her." }, hold: "Hold E to dash out of her all-in \u2014 deny her combo; Q-poke her off the shroud.", tip: "Build MR, Q-poke her off her shroud, and E-dash out of her all-in.", win: "Build MR and poke her off shroud." },
