  gangplank: { diff: "EVEN", tone: "#e8b84b", tldr: "Poke war \u2014 pop his barrels, E-dash his engage.", breakdown: "Pop his barrels, win the Q-poke war, and E-dash out of his engage.", dos: ["Pop his barrels", "Win the poke war", "E-dash out of his engage"], donts: ["Eat a full barrel chain", "Let him free-scale", "Get stuck in melee"], key: { slot: "E", name: "Powder Kegs", cd: "18s", note: "Pop barrels to deny poke + gold.", winT: "BARRELS CLEARED", winS: "Stun-stack + R him." }, hold: "Hold E to dash out as he steps to a barrel \u2014 deny his combo and win the poke war.", tip: "Pop his barrels, win the Q-poke war, and E-dash out of his engage.", win: "Win the poke war and pop his barrels." },
  gnar: { diff: "EVEN", tone: "#e8b84b", tldr: "Poke mini \u2014 E-dash Mega, win the poke war.", breakdown: "Q-poke mini Gnar, E-dash out of his Mega all-in, and win the poke war.", dos: ["Q-poke mini Gnar", "E-dash out of his Mega all-in", "Win the poke war"], donts: ["Get kited in mini form", "Fight Mega\u2019s all-in raw", "Get stuck in melee"], key: { slot: "R", name: "GNAR! (Mega Stun)", cd: "90s", note: "His Mega all-in. E-dash it.", winT: "MINI FORM", winS: "Stun-stack + R him." }, hold: "Hold E to dash out of his Mega all-in \u2014 deny his GNAR! engage; poke mini Gnar.", tip: "Q-poke mini Gnar, E-dash out of his Mega all-in, and win the poke war.", win: "Poke mini and dash Mega." },
  heimerdinger: { diff: "TRICKY", tone: "#ff8b3d", tldr: "His turrets out-poke you \u2014 build MR, E-dash in.", breakdown: "Heimer\u2019s turrets out-poke you. Build MR, Q his turrets, E-dash onto him off his nest, and stun-stack.", dos: ["Build MR", "Q his turrets", "E-dash him off his nest"], donts: ["Dive a full nest raw", "Eat his E stun", "Poke-war into turrets"], key: { slot: "E", name: "CH-2 Grenade (Stun)", cd: "11s", note: "His self-peel stun. Dodge it.", winT: "GRENADE DOWN", winS: "Stun-stack + R him." }, hold: "Hold E to dash onto him off his nest \u2014 separate him from turrets, then stun-stack + R.", tip: "Q his turrets, build MR, and E-dash onto him off his nest \u2014 then stun-lock him with R.", win: "Build MR and dash onto him." },
