  kayle: { diff: "FAVOURED", tone: "#3ddc97", tldr: "Crush her early \u2014 Q-poke and deny her CS.", breakdown: "Kayle is helpless early. Q-poke and zone her off CS, and all-in before her R.", dos: ["Q-poke and zone her", "Deny her CS + XP", "All-in before her R"], donts: ["Let her free-farm", "Fight late vs her R", "Get stuck in melee"], key: { slot: "R", name: "Divine Judgment (Invuln)", cd: "100s", note: "Her get-out at 6. Bait it.", winT: "JUDGMENT DOWN", winS: "Stun-stack + R her." }, hold: "Hold E to dash onto her off CS \u2014 zone her off farm and all-in before she scales.", tip: "She\u2019s helpless early \u2014 Q-poke her off CS and all-in before her R; deny her scaling.", win: "Bully her early and deny CS." },
  kennen: { diff: "MIRROR", tone: "#e8b84b", tldr: "Kennen mirror \u2014 whoever wins the Q-poke war and stun-locks first wins.", breakdown: "Pure Kennen mirror: it\u2019s a Q-poke and stun-stack race. Whoever out-pokes and lands the full stun + R first wins.", dos: ["Win the Q-poke war", "Stun-stack first", "Build MR vs his poke"], donts: ["Get stun-locked first", "Eat his Q poke", "Fall behind in farm"], key: { slot: "E", name: "Lightning Rush", cd: "10s", note: "Whoever out-pokes + stun-locks first wins.", winT: "E DOWN", winS: "Stun-stack + R him." }, hold: "Hold E to dash in/out \u2014 whoever wins the Q-poke war and lands the full stun + R first wins.", tip: "It\u2019s a Q-poke and stun-lock mirror \u2014 win the poke war, build MR, and stun-stack him first.", win: "Win the poke war and stun first." },
  quinn: { diff: "EVEN", tone: "#e8b84b", tldr: "Poke war \u2014 E-dash onto her, all-in early.", breakdown: "Quinn out-pokes and kites. Win the Q-poke war, E-dash onto her, and all-in early.", dos: ["Win the Q-poke war", "E-dash onto her", "All-in early"], donts: ["Fight into her blind", "Let her kite you out", "Get stuck in poke range"], key: { slot: "E", name: "Vault (Dash/Blind)", cd: "11s", note: "Her self-peel. All-in when it\u2019s down.", winT: "VAULT DOWN", winS: "Stun-stack + R her." }, hold: "Hold E to dash onto her \u2014 close the gap she\u2019s kiting, then stun-stack + R.", tip: "Win the Q-poke war, E-dash onto her, and all-in early before she scales.", win: "Win the poke war and dash onto her." },
  rumble: { diff: "EVEN", tone: "#e8b84b", tldr: "Build MR \u2014 poke war, E-dash his engage, dodge R.", breakdown: "Build MR, win the Q-poke war, E-dash out of his engage, and dodge his R line.", dos: ["Build MR", "Win the poke war", "Dodge his R line"], donts: ["Extend into his danger-zone Q", "Stand in his R line", "Fight in his flamespitter"], key: { slot: "W", name: "Scrap Shield", cd: "6s", note: "Bait it, then commit.", winT: "SHIELD DOWN", winS: "Stun-stack + R him." }, hold: "Hold E to dash out of his engage \u2014 build MR; win the poke war and dodge his R.", tip: "Build MR, win the Q-poke war, E-dash out of his engage, and dodge his Equalizer.", win: "Build MR and win the poke war." },
  singed: { diff: "EVEN", tone: "#e8b84b", tldr: "Don\u2019t chase poison \u2014 poke from range, E-dash his fling.", breakdown: "Never chase through poison. Q-poke from range, and E-dash out when he commits a fling.", dos: ["Q-poke from range", "E-dash out of his fling", "Punish his proxy waves"], donts: ["Chase through his Q poison", "Get E-flipped into goo", "Get stuck in melee"], key: { slot: "E", name: "Fling", cd: "14s", note: "His flip. E-dash/dodge it.", winT: "FLING DOWN", winS: "Stun-stack + R him." }, hold: "Hold E to dash out when he commits a fling \u2014 deny the flip and punish him.", tip: "Don\u2019t chase his poison \u2014 Q-poke from range and E-dash out of his fling.", win: "Poke him out and dash his fling." },
  swain: { diff: "EVEN", tone: "#e8b84b", tldr: "Build MR \u2014 poke war, E-dash his E root.", breakdown: "Build MR, win the Q-poke war, E-dash out of his E root, and anti-heal his R drain.", dos: ["Build MR + anti-heal", "Win the poke war", "E-dash out of his E root"], donts: ["Fight into his R drain", "Get E-rooted", "Get stuck in melee"], key: { slot: "R", name: "Demonic Ascension", cd: "100s", note: "His drain. Poke when it\u2019s down.", winT: "ASCENSION DOWN", winS: "Stun-stack + R him." }, hold: "Hold E to dash out of his E root \u2014 build MR; win the poke war.", tip: "Build MR, win the Q-poke war, E-dash out of his E root, and anti-heal his R drain.", win: "Build MR and win the poke war." },
  teemo: { diff: "EVEN", tone: "#e8b84b", tldr: "Poke war \u2014 build MR, out-range his blind, dodge shrooms.", breakdown: "Teemo blinds autos (not your Q). Build MR, out-poke him with Q, and dodge shrooms.", dos: ["Build MR + dodge shrooms", "Q out-poke him", "E-dash onto him"], donts: ["Auto into his blind", "Chase through shrooms", "Get stuck in melee"], key: { slot: "Q", name: "Blinding Dart", cd: "7s", note: "Blinds autos \u2014 NOT your Q shuriken.", winT: "BLIND DOWN", winS: "Stun-stack + R him." }, hold: "Hold E to dash onto him \u2014 his blind stops autos but not your Q; out-poke him.", tip: "His blind only stops autos \u2014 out-poke him with Q (it ignores blind), build MR, and dodge shrooms.", win: "Out-poke him through his blind." },
  vladimir: { diff: "EVEN", tone: "#e8b84b", tldr: "Bully him early \u2014 build MR, poke, bait pool.", breakdown: "Vlad is weak early. Build MR, Q-poke and bully him, and bait his pool.", dos: ["Q-poke and bully early", "Build MR + anti-heal", "Bait his pool"], donts: ["Let him pool your combo", "Stack pure HP vs %damage", "Let him free-scale"], key: { slot: "W", name: "Sanguine Pool", cd: "22s", note: "Dodges your combo. Bait it.", winT: "POOL DOWN", winS: "Stun-stack + R him." }, hold: "Hold your R \u2014 bait his pool with Q poke first, then stun-stack + R when it\u2019s down.", tip: "He\u2019s weak early \u2014 Q-poke and bully him, bait his pool, and stun-stack when it\u2019s down.", win: "Bully him early and bait his pool." },
