  // ===== OFF-META & FLEX PICKS =====
  akshan: {"diff":"EVEN","tone":"#e8b84b","tldr":"Weather the poke — poke stun-stacks and R his Heroic Swing commit.","breakdown":"Akshan plays around Heroic Swing. Shuriken chip builds marks — third proc stuns. Hold E for his Heroic Swing, and the R dive wins any 2v2 top. Doran’s Shield blunts the poke war.","dos":["Q-poke on cooldown","Stack stuns before committing","R + Zhonya the all-in"],"donts":["Burn E without a stun plan","Trade in melee with W down","Waste R on one target"],"key":{"slot":"E","name":"Heroic Swing","cd":"14s","note":"His dash + camera swing escape. Engage when it's down.","winT":"SWING DOWN","winS":"3-stun rotation + R dive."},"win":"Poke stun-stacks and R his Heroic Swing commit."},
  cassiopeia: {"diff":"TRICKY","tone":"#ff8b3d","tldr":"Weather the poke — poke stun-stacks and R his Miasma commit.","breakdown":"Cassiopeia plays around Miasma. Shuriken chip builds marks — third proc stuns. Hold E for his Miasma, and the R dive wins any 2v2 top. Take Mercs / MR shard — his damage is magic. Doran’s Shield blunts the poke war.","dos":["Q-poke on cooldown","Stack stuns before committing","R + Zhonya the all-in"],"donts":["Burn E without a stun plan","Trade in melee with W down","Waste R on one target"],"key":{"slot":"W","name":"Miasma","cd":"12s","note":"Grounds you — dashes and movement abilities are disabled inside it.","winT":"MIASMA DOWN","winS":"3-stun rotation + R dive."},"win":"Poke stun-stacks and R his Miasma commit."},
  galio: {"diff":"EVEN","tone":"#e8b84b","tldr":"Bait his key tool — poke stun-stacks and R his Justice Punch commit.","breakdown":"Galio plays around Justice Punch. Shuriken chip builds marks — third proc stuns. Hold E for his Justice Punch, and the R dive wins any 2v2 top. Take Mercs / MR shard — his damage is magic.","dos":["Q-poke on cooldown","Stack stuns before committing","R + Zhonya the all-in"],"donts":["Burn E without a stun plan","Trade in melee with W down","Waste R on one target"],"key":{"slot":"E","name":"Justice Punch","cd":"13s","note":"His dash + knockup engage. Punish him when it's down.","winT":"JUSTICE PUNCH DOWN","winS":"3-stun rotation + R dive."},"win":"Poke stun-stacks and R his Justice Punch commit."},
